import { PointsProduct } from "../../../ducks/points";

export interface ParameterizationResponse {
  data: {
    serviceMessage: {
      codigoRetorno: number;
      mensagem: string;
    };
    error: {}
    status: {
      sessionId: string;
    }
    data: ParametrizationData[];
  }
}

export interface ParametrizationData {
  category: string;
  value: string;
  dateCreated: string | Date;
  PK: string;
  dateUpdated: string | Date;
  status: number;
}

export interface ProductResponse {
  data: {
    data: { products?: PointsProduct[] };
    status: {
      returnCode?: number;
      codigoRetorno?: number;
      message?: string;
    };
  };
}

